const raw = items[0].json.candidates[0].content.parts[0].text;

const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No JSON found in response: ' + raw);
}

const parsed = JSON.parse(jsonMatch[0]);
return [{ json: parsed }];

