const feedbackUrl = `http://localhost:5678/form/220f1e63-15aa-4788-857e-1836ad71ae61?email=${encodeURIComponent(travelerEmail)}&destination=${encodeURIComponent(destination)}`;

// Feedback button HTML
const feedbackHtml = `
<div style="text-align:center; margin-top:30px; padding:20px; 
            background-color:#f0f7ff; border-radius:8px; 
            border: 1px solid #d0e8ff;">
  <p style="font-size:16px; color:#333; margin-bottom:12px;">
    Want to refine your itinerary?
  </p>
  <a href="${feedbackUrl}" 
     style="background-color:#0056b3; color:white; padding:12px 28px; 
            text-decoration:none; border-radius:5px; font-size:14px; 
            font-weight:bold; display:inline-block;">
    ✏️ Refine My Itinerary
  </a>
</div>`;

return [{ 
  json: { 
    html_body: text + feedbackHtml,
    traveler_email: travelerEmail,
    destination: destination
  } 
}];

